#!/bin/bash
set -e
echo "🚀 Installing AIPGBD v5..."

# Navigate to projects folder
cd /e/Projects

# Remove old install if exists
rm -rf aipgbd-react-site

# Create React App
echo "📦 Creating React app (3-5 min)..."
npx create-react-app aipgbd-react-site --template cra-template 2>/dev/null
cd aipgbd-react-site

# Create directories
mkdir -p src/components src/data src/hooks src/styles public

# Write all files via base64 decode
echo "📝 Writing project files..."

python3 -c "import base64; open('package.json','wb').write(base64.b64decode(''))"
mkdir -p public
python3 -c "import base64; open('public/index.html','wb').write(base64.b64decode(''))"
mkdir -p src
python3 -c "import base64; open('src/App.js','wb').write(base64.b64decode(''))"
mkdir -p src
python3 -c "import base64; open('src/index.js','wb').write(base64.b64decode('aW1wb3J0IFJlYWN0IGZyb20gJ3JlYWN0JzsKaW1wb3J0IFJlYWN0RE9NIGZyb20gJ3JlYWN0LWRvbS9jbGllbnQnOwppbXBvcnQgQXBwIGZyb20gJy4vQXBwJzsKCmNvbnN0IHJvb3QgPSBSZWFjdERPTS5jcmVhdGVSb290KGRvY3VtZW50LmdldEVsZW1lbnRCeUlkKCdyb290JykpOwpyb290LnJlbmRlcig8UmVhY3QuU3RyaWN0TW9kZT48QXBwIC8+PC9SZWFjdC5TdHJpY3RNb2RlPik7Cg=='))"
mkdir -p src/styles
python3 -c "import base64; open('src/styles/globals.css','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/Navbar.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/Process.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/Contact.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/Footer.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/Industries.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/AdminPanel.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/Hero.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/FAQ.js','wb').write(base64.b64decode(''))"
mkdir -p src/components
python3 -c "import base64; open('src/components/Services.js','wb').write(base64.b64decode(''))"
mkdir -p src/hooks
python3 -c "import base64; open('src/hooks/db.js','wb').write(base64.b64decode(''))"

echo "✅ All files written!"
echo "📦 Installing npm packages..."
npm install
echo ""
echo "🎉 DONE! Starting dev server..."
echo "🌐 Open http://localhost:3000 in your browser"
echo "⚙  Admin: click the ⚙ icon in nav, PIN: 1234"
echo ""
npm start